    tracks: ['CCA'],
    level: 'L3',
    practiceId: 'CM.L3-3.4.2e',
    domain: 'CM',
    difficulty: 3,
    stem: 'A defense contractor receives a shipment of network switches for installation in their CUI processing environment. Under CM.L3-3.4.2e, what must occur before the switches are placed into production?',
