export function getQuestionsByFilter({
  tracks,
  level,
  domain,
  limit,
  includeIds,
}: {
  tracks?: string[]
  level?: string
  domain?: string
  limit?: number
  /** If provided, only return questions with these IDs (used by missedReview) */
  includeIds?: string[]
}): Question[] {
  let questions = [...SEED_QUESTIONS]

  if (includeIds && includeIds.length > 0) {
    const idSet = new Set(includeIds)
    questions = questions.filter(q => idSet.has(q.id))
  } else {
    if (tracks && tracks.length > 0) {
      questions = questions.filter(q => q.tracks.some(t => tracks.includes(t)))
    }
    if (level) {
      questions = questions.filter(q => q.level === level)
    }
    if (domain && domain !== 'mixed') {
      questions = questions.filter(q => q.domain === domain)
    }
  }

  // Shuffle
  questions = questions.sort(() => Math.random() - 0.5)

  if (limit) {
    questions = questions.slice(0, limit)
  }

  return questions
}
